import React from 'react';

// Компонент для стрелки "Вперед"
function NextArrow(props) {
  const { className, style, onClick } = props; // Получаем свойства от react-slick

  return (
    <div
      className={className} // !!! ВАЖНО: Сохраняем этот класс для стилизации
      style={{
        ...style, // !!! ВАЖНО: Сохраняем стили от react-slick (они отвечают за базовое позиционирование)
        // Теперь добавляем свои стили для внешнего вида и точного позиционирования
        display: 'flex', // Используем flex для центрирования содержимого
        justifyContent: 'center', // Центрируем по горизонтали
        alignItems: 'center', // Центрируем по вертикали
        position: 'absolute', // Делаем стрелку абсолютно позиционированной относительно слайдера
        right: '10px', // Пример: смещаем на 10px от правого края
        top: '50%', // Размещаем по центру по вертикали
        transform: 'translateY(-50%)', // Корректируем позиционирование по вертикали, чтобы центр был точно посередине
        zIndex: 10, // Убеждаемся, что стрелка поверх слайдов
        width: '40px', // Пример: задаем размер стрелки
        height: '40px',
        backgroundColor: 'rgba(0,0,0,0.5)', // Полупрозрачный фон
        borderRadius: '50%', // Делаем круглыми
        color: 'white', // Цвет текста/иконки
        cursor: 'pointer', // Указываем, что это кликабельный элемент
        fontSize: '20px', // Размер текста
        transition: 'background-color 0.3s ease', // Плавный переход при наведении
      }}
      onClick={onClick} // !!! ВАЖНО: Передаем функцию onClick, чтобы слайдер переключался
    >
      &gt; {/* Ваш символ стрелки "вперед" */}
    </div>
  );
}

// Компонент для стрелки "Назад"
function PrevArrow(props) {
  const { className, style, onClick } = props; // Получаем свойства от react-slick

  return (
    <div
      className={className} // !!! ВАЖНО: Сохраняем этот класс для стилизации
      style={{
        ...style, // !!! ВАЖНО: Сохраняем стили от react-slick
        // Теперь добавляем свои стили для внешнего вида и точного позиционирования
        display: 'flex',
        justifyContent: 'center',
        alignItems: 'center',
        position: 'absolute', // Делаем стрелку абсолютно позиционированной
        left: '10px', // Пример: смещаем на 10px от левого края
        top: '50%',
        transform: 'translateY(-50%)',
        zIndex: 10,
        width: '40px',
        height: '40px',
        backgroundColor: 'rgba(0,0,0,0.5)',
        borderRadius: '50%',
        color: 'white',
        cursor: 'pointer',
        fontSize: '20px',
        transition: 'background-color 0.3s ease',
      }}
      onClick={onClick} // !!! ВАЖНО: Передаем функцию onClick
    >
      &lt; {/* Ваш символ стрелки "назад" */}
    </div>
  );
}

export { NextArrow, PrevArrow }; // Экспортируем компоненты
